mapper.select:
SELECT
t.*,
t1.real_name create_user_name
FROM
member_tag t
LEFT OUTER JOIN castle_sys_user t1 ON t.create_user  = t1.id
WHERE
t.is_deleted = 2

    AND t.id = #{memberTagEntity.id}


    AND t.name like concat('%',#{memberTagEntity.name},'%')


    AND t.status = #{memberTagEntity.status}


    AND t.create_user = #{memberTagEntity.createUser}


    AND t.create_time = #{memberTagEntity.createTime}


    AND t.update_user = #{memberTagEntity.updateUser}


    AND t.update_time = #{memberTagEntity.updateTime}


    AND t.is_deleted = #{memberTagEntity.isDeleted}


    AND t.sort = #{memberTagEntity.sort}

    order by sort desc,create_time desc

    limit #{map.offset},#{map.rows}

SELECT
    count(1)
FROM
member_tag t
WHERE
    t.is_deleted = 2

    AND t.id = #{memberTagEntity.id}


    AND t.name like concat('%',#{memberTagEntity.name},'%')


    AND t.status = #{memberTagEntity.status}


    AND t.create_user = #{memberTagEntity.createUser}


    AND t.create_time = #{memberTagEntity.createTime}


    AND t.update_user = #{memberTagEntity.updateUser}


    AND t.update_time = #{memberTagEntity.updateTime}


    AND t.is_deleted = #{memberTagEntity.isDeleted}


    AND t.sort = #{memberTagEntity.sort}
